const inputItems = $input.all();

const preferredKeys = [
  'Веб-сайт 1',
  'Веб-сайт 2',
  'Веб-сайт 3',
  'Веб-сайт',
  '2GIS URL',
  'Сайт 1',
  'Сайт 2',
  'Сайт 3',
  'Сайт',
  'Website 1',
  'Website 2',
  'Website 3',
  'Website',
  'Site 1',
  'Site 2',
  'Site 3',
  'Site',
  'URL',
  'Url',
  'url',
  'Вконтакте',
  'VK',
  'vk'
];

const hintKeyRegex = /(сайт|веб|website|site|url|вк|vk|instagram|facebook|telegram|linkedin)/i;
const socialHostRegex = /^(?:www\.)?(vk\.com|m\.vk\.com|t\.me|telegram\.me|instagram\.com|facebook\.com|linkedin\.com)$/i;
const deepPaths = [
  '/contacts',
  '/contact',
  '/about',
  '/about-us',
  '/company/contacts',
  '/kontakty',
  '/o-kompanii',
  '/ru/contacts'
];

const maxSeedUrlsPerRow = 6;
const maxCrawlUrlsPerRow = 20;

const clean = (value) => String(value ?? '').trim();

const trimToken = (value) =>
  clean(value).replace(/^[\s"'<>()[\]{}]+|[\s"'<>()[\]{}.,;:!]+$/g, '');

const normalizeUrl = (value) => {
  let normalized = trimToken(value);
  if (!normalized) return '';

  if (!/^https?:\/\//i.test(normalized)) {
    normalized = 'https://' + normalized.replace(/^\/+/, '');
  }

  try {
    const parsed = new URL(normalized);
    if (!parsed.hostname || !parsed.hostname.includes('.')) return '';
    parsed.hash = '';
    return parsed.toString();
  } catch {
    return '';
  }
};

const canonicalUrlKey = (url) => {
  try {
    const parsed = new URL(url);
    const host = parsed.hostname.toLowerCase();
    const pathname = parsed.pathname.replace(/\/+$/g, '') || '/';
    const search = parsed.search || '';
    return host + pathname + search;
  } catch {
    return String(url || '').toLowerCase();
  }
};

const extractUrlTokens = (value) => {
  const raw = clean(value);
  if (!raw) return [];

  const tokens = new Set();

  const splitParts = raw
    .split(/[\n,;|]+/)
    .map(trimToken)
    .filter(Boolean);

  for (const part of splitParts) {
    const normalized = normalizeUrl(part);
    if (normalized) tokens.add(normalized);
  }

  const directMatches = raw.match(/https?:\/\/[^\s"'<>]+/gi) || [];
  for (const match of directMatches) {
    const normalized = normalizeUrl(match);
    if (normalized) tokens.add(normalized);
  }

  const domainMatches = raw.match(/(?:[a-z0-9-]+\.)+[a-z]{2,}(?:\/[^\s"'<>]*)?/gi) || [];
  for (const match of domainMatches) {
    const normalized = normalizeUrl(match);
    if (normalized) tokens.add(normalized);
  }

  return Array.from(tokens);
};

const buildSearchFallbackUrl = (row) => {
  const query = [
    clean(row['Наименование'] ?? row['Название'] ?? row['name']),
    clean(row['Город'] ?? row['city']),
    clean(row['Телефон 1'] ?? row['Телефон'] ?? row['phone'])
  ]
    .filter(Boolean)
    .join(' ');

  if (!query) return '';

  return 'https://duckduckgo.com/html/?q=' + encodeURIComponent(query + ' официальный сайт контакты email vk');
};

const buildDeepEntries = (seedUrl) => {
  const deepEntries = [];

  try {
    const parsed = new URL(seedUrl);
    const host = parsed.hostname.toLowerCase();

    if (socialHostRegex.test(host)) {
      if (/vk\.com$|m\.vk\.com$/i.test(host)) {
        const slug = parsed.pathname.replace(/^\/+|\/+$/g, '');
        if (slug) {
          const mobileUrl = normalizeUrl('https://m.vk.com/' + slug);
          if (mobileUrl) {
            deepEntries.push({ url: mobileUrl, depth: 1, source: 'vk-mobile' });
          }
        }
      }
      return deepEntries;
    }

    const origin = parsed.origin;
    for (const path of deepPaths) {
      const deepUrl = normalizeUrl(origin + path);
      if (deepUrl) {
        deepEntries.push({ url: deepUrl, depth: 1, source: 'deep:' + path });
      }
    }
  } catch {
    return deepEntries;
  }

  return deepEntries;
};

const outputItems = [];

inputItems.forEach((item, sourceIndex) => {
  const row = item.json || {};
  const seedCanonicalSet = new Set();
  const seedCandidates = [];

  const pushSeed = (url, sourceTag) => {
    if (!url || seedCandidates.length >= maxSeedUrlsPerRow) return;

    const key = canonicalUrlKey(url);
    if (!key || seedCanonicalSet.has(key)) return;

    seedCanonicalSet.add(key);
    seedCandidates.push({ url, sourceTag });
  };

  for (const key of preferredKeys) {
    if (seedCandidates.length >= maxSeedUrlsPerRow) break;
    if (!Object.prototype.hasOwnProperty.call(row, key)) continue;

    const urls = extractUrlTokens(row[key]);
    for (const url of urls) {
      pushSeed(url, 'key:' + key);
      if (seedCandidates.length >= maxSeedUrlsPerRow) break;
    }
  }

  if (seedCandidates.length < maxSeedUrlsPerRow) {
    for (const [key, value] of Object.entries(row)) {
      if (seedCandidates.length >= maxSeedUrlsPerRow) break;
      if (!hintKeyRegex.test(key)) continue;

      const urls = extractUrlTokens(value);
      for (const url of urls) {
        pushSeed(url, 'hint:' + key);
        if (seedCandidates.length >= maxSeedUrlsPerRow) break;
      }
    }
  }

  if (seedCandidates.length < maxSeedUrlsPerRow) {
    for (const value of Object.values(row)) {
      if (seedCandidates.length >= maxSeedUrlsPerRow) break;

      const urls = extractUrlTokens(value);
      for (const url of urls) {
        pushSeed(url, 'any-value');
        if (seedCandidates.length >= maxSeedUrlsPerRow) break;
      }
    }
  }

  if (seedCandidates.length === 0) {
    const fallback = normalizeUrl(buildSearchFallbackUrl(row));
    if (fallback) {
      pushSeed(fallback, 'search-fallback');
    }
  }

  const crawlSet = new Set();
  const crawlEntries = [];

  const pushCrawl = (entry, seed, seedIndex) => {
    if (!entry?.url || crawlEntries.length >= maxCrawlUrlsPerRow) return;

    const key = canonicalUrlKey(entry.url);
    if (!key || crawlSet.has(key)) return;

    crawlSet.add(key);

    let targetHost = '';
    try {
      targetHost = new URL(entry.url).hostname.replace(/^www\./i, '').toLowerCase();
    } catch {
      targetHost = '';
    }

    crawlEntries.push({
      json: {
        ...row,
        targetUrl: entry.url,
        targetHost,
        seed_url: seed.url,
        seed_source: seed.sourceTag,
        crawl_depth: entry.depth,
        url_source: entry.depth === 0 ? seed.sourceTag : entry.source,
        url_detected: true,
        source_row_index: sourceIndex,
        source_url_rank: seedIndex + 1,
        source_urls_count: seedCandidates.length,
      },
      pairedItem: { item: sourceIndex },
    });
  };

  const deepPerSeed = [];

  for (let seedIndex = 0; seedIndex < seedCandidates.length; seedIndex++) {
    const seed = seedCandidates[seedIndex];
    pushCrawl({ url: seed.url, depth: 0, source: 'seed' }, seed, seedIndex);
    deepPerSeed[seedIndex] = buildDeepEntries(seed.url);
  }

  let deepCursor = 0;
  let addedAny = true;

  while (crawlEntries.length < maxCrawlUrlsPerRow && addedAny) {
    addedAny = false;

    for (let seedIndex = 0; seedIndex < seedCandidates.length; seedIndex++) {
      if (crawlEntries.length >= maxCrawlUrlsPerRow) break;

      const deepList = deepPerSeed[seedIndex] || [];
      const deepEntry = deepList[deepCursor];
      if (!deepEntry) continue;

      pushCrawl(deepEntry, seedCandidates[seedIndex], seedIndex);
      addedAny = true;
    }

    deepCursor += 1;
  }

  if (crawlEntries.length === 0) {
    outputItems.push({
      json: {
        ...row,
        targetUrl: '',
        targetHost: '',
        seed_url: '',
        seed_source: 'none',
        crawl_depth: 0,
        url_source: 'none',
        url_detected: false,
        source_row_index: sourceIndex,
        source_url_rank: 1,
        source_urls_count: 1,
      },
      pairedItem: { item: sourceIndex },
    });
  } else {
    outputItems.push(...crawlEntries);
  }
});

return outputItems;

const inputItems = $input.all();
const sourceItems = $items('Select URL', 0, $runIndex) || [];
const emailRegex = /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi;
const obfuscatedEmailRegex = /([a-z0-9._%+-]+)\s*(?:\[at\]|\(at\)|\sat\s|\{@\})\s*([a-z0-9.-]+)\s*(?:\[dot\]|\(dot\)|\sdot\s|\{\.\})\s*([a-z]{2,})/gi;

const blockedDomains = [
  '2gis.ru',
  'wixpress.com',
  'sentry.io',
  'cloudflare.com',
  'google.com',
  'google.ru',
  'yandex.ru',
  'duckduckgo.com',
  'bing.com',
  'example.com',
  'example.org',
  'example.net'
];

const blockedLocalStarts = ['noreply', 'no-reply', 'donotreply', 'do-not-reply'];

const normalizeEmail = (value) =>
  String(value)
    .toLowerCase()
    .replace(/^[\s"'<>()[\]{}.,;:!]+|[\s"'<>()[\]{}.,;:!]+$/g, '');

const isBlocked = (email) => {
  if (!email || !email.includes('@')) return true;

  const [local, domainRaw] = email.split('@');
  const domain = String(domainRaw || '').toLowerCase();
  const localPart = String(local || '').toLowerCase();

  if (!localPart || !domain) return true;
  if (blockedLocalStarts.some((prefix) => localPart.startsWith(prefix))) return true;

  return blockedDomains.some((blocked) => domain === blocked || domain.endsWith('.' + blocked));
};

const resolvePairedIndex = (item, fallbackIndex) => {
  const paired = item.pairedItem;

  if (typeof paired === 'number') return paired;
  if (paired && typeof paired === 'object' && typeof paired.item === 'number') return paired.item;
  if (Array.isArray(paired) && paired[0] && typeof paired[0].item === 'number') return paired[0].item;

  return fallbackIndex;
};

const decodeHtmlEntitiesLite = (text) =>
  String(text)
    .replace(/&commat;/gi, '@')
    .replace(/&#64;/g, '@')
    .replace(/&#x40;/gi, '@')
    .replace(/&dot;/gi, '.')
    .replace(/&#46;/g, '.')
    .replace(/&#x2e;/gi, '.');

const extractEmailsFromText = (text) => {
  const found = new Set();

  const raw = String(text || '');
  const decodedEntity = decodeHtmlEntitiesLite(raw);
  let decodedUri = decodedEntity;

  try {
    decodedUri = decodeURIComponent(decodedEntity);
  } catch {
    decodedUri = decodedEntity;
  }

  const variants = [raw, decodedEntity, decodedUri];

  for (const variant of variants) {
    const normalizedVariant = String(variant || '');

    const normalMatches = normalizedVariant.match(emailRegex) || [];
    for (const match of normalMatches) {
      const email = normalizeEmail(match);
      if (email && !isBlocked(email)) found.add(email);
    }

    const mailtoMatches = normalizedVariant.match(/mailto:[^\s"'<>]+/gi) || [];
    for (const match of mailtoMatches) {
      const rawMail = match.replace(/^mailto:/i, '').split('?')[0];
      const email = normalizeEmail(rawMail);
      if (email && !isBlocked(email)) found.add(email);
    }

    for (const obf of normalizedVariant.matchAll(obfuscatedEmailRegex)) {
      const local = normalizeEmail(obf[1] || '');
      const domain = normalizeEmail(obf[2] || '');
      const zone = normalizeEmail(obf[3] || '');
      const reconstructed = normalizeEmail(local + '@' + domain + '.' + zone);
      if (reconstructed && !isBlocked(reconstructed)) found.add(reconstructed);
    }
  }

  return Array.from(found);
};

const buckets = new Map();

for (let idx = 0; idx < inputItems.length; idx++) {
  const item = inputItems[idx];
  const inputIndex = resolvePairedIndex(item, idx);
  const sourceRow = sourceItems[inputIndex]?.json || {};
  const currentJson = item.json || {};
  const mergedJson = { ...sourceRow, ...currentJson };

  const explicitSourceIndex = Number(mergedJson.source_row_index);
  const sourceIndex = Number.isInteger(explicitSourceIndex) && explicitSourceIndex >= 0
    ? explicitSourceIndex
    : inputIndex;

  if (!buckets.has(sourceIndex)) {
    buckets.set(sourceIndex, {
      mergedJson: { ...mergedJson },
      emailsSet: new Set(),
      fetchedUrls: new Set(),
      hasFetchError: false,
    });
  }

  const bucket = buckets.get(sourceIndex);
  bucket.mergedJson = { ...bucket.mergedJson, ...mergedJson };

  const htmlRaw = String(
    mergedJson.html ?? mergedJson.body ?? mergedJson.data ?? mergedJson.response ?? ''
  );

  const prepared = htmlRaw
    .replace(/<script\b[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style\b[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<!--([\s\S]*?)-->/g, ' ');

  const extracted = extractEmailsFromText(prepared);
  for (const email of extracted) {
    bucket.emailsSet.add(email);
  }

  const fetchedUrl = String(mergedJson.targetUrl || '').trim();
  if (fetchedUrl) bucket.fetchedUrls.add(fetchedUrl);

  if (mergedJson.error) {
    bucket.hasFetchError = true;
  }
}

const sourceIndexes = Array.from(buckets.keys()).sort((a, b) => a - b);

return sourceIndexes.map((sourceIndex) => {
  const bucket = buckets.get(sourceIndex);
  const mergedJson = { ...bucket.mergedJson };
  const deduped = Array.from(bucket.emailsSet);

  mergedJson.source_row_index = sourceIndex;
  mergedJson.parsed_urls = Array.from(bucket.fetchedUrls);
  mergedJson.parsed_urls_count = mergedJson.parsed_urls.length;

  mergedJson.emails_array = deduped;
  mergedJson.emails_string = deduped.join(', ');
  mergedJson.email_1 = deduped[0] || '';
  mergedJson.email_2 = deduped[1] || '';
  mergedJson.ID = mergedJson.ID ?? '';

  mergedJson.parse_status = deduped.length > 0
    ? 'emails_found'
    : bucket.hasFetchError
      ? 'fetch_error_or_no_email'
      : 'no_email_found';

  delete mergedJson.html;
  delete mergedJson.body;
  delete mergedJson.data;
  delete mergedJson.response;

  return {
    json: mergedJson,
    pairedItem: { item: sourceIndex },
  };
});

